251→/**
252→ * Updates or inserts a new whitespace element with [text] before the given node. If the node itself is a whitespace
253→ * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
254→ * added after the previous leaf node.
255→ */
256→public fun ASTNode.upsertWhitespaceBeforeMe(text: String) {
257→    if (this is LeafElement) {
258→        if (this.elementType == WHITE_SPACE) {
259→            return replaceWhitespaceWith(text)
260→        }
261→        val previous = treePrev ?: prevLeaf()
262→        if (previous != null && previous.elementType == WHITE_SPACE) {
263→            previous.replaceWhitespaceWith(text)
264→        } else {
265→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
266→                (psi as LeafElement).rawInsertBeforeMe(psiWhiteSpace)
267→            }
268→        }
269→    } else {
270→        val prevLeaf =
271→            requireNotNull(prevLeaf()) {
272→                "Can not upsert a whitespace if the first node is a non-leaf node"
273→            }
274→        prevLeaf.upsertWhitespaceAfterMe(text)
275→    }
276→}
277→
278→private fun ASTNode.replaceWhitespaceWith(text: String) {
279→    require(this.elementType == WHITE_SPACE)
280→    if (this.text != text) {
281→        (this.psi as LeafElement).rawReplaceWithText(text)
282→    }
283→}
284→
285→/**
286→ * Updates or inserts a new whitespace element with [text] after the given node. If the node itself is a whitespace
287→ * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
288→ * added after the last child leaf.
289→ */
290→public fun ASTNode.upsertWhitespaceAfterMe(text: String) {
291→    if (this is LeafElement) {
292→        if (this.elementType == WHITE_SPACE) {
293→            return replaceWhitespaceWith(text)
294→        }
295→        val next = treeNext ?: nextLeaf()
296→        if (next != null && next.elementType == WHITE_SPACE) {
297→            next.replaceWhitespaceWith(text)
298→        } else {
299→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
300→                (psi as LeafElement).rawInsertAfterMe(psiWhiteSpace)
301→            }
302→        }
303→    } else {
304→        lastChildLeafOrSelf().upsertWhitespaceAfterMe(text)
305→    }
306→}
