308→public val ASTNode.column: Int
309→    get() {
310→        var leaf = this.prevLeaf()
311→        var offsetToTheLeft = 0
312→        while (leaf != null) {
313→            if ((leaf.elementType == WHITE_SPACE || leaf.elementType == REGULAR_STRING_PART) && leaf.textContains('\n')) {
314→                offsetToTheLeft += leaf.textLength - 1 - leaf.text.lastIndexOf('\n')
315→                break
316→            }
317→            offsetToTheLeft += leaf.textLength
318→            leaf = leaf.prevLeaf()
319→        }
320→        return offsetToTheLeft + 1
321→    }
