419→/**
420→ * Creates a sequences of leaves including the [ASTNode] in case it is a [LeafElement] itself. By default, the leaves are traversed in
421→ * forward order. Setting [forward] to `false` changes this to traversal in backward direction.
422→ */
423→public fun ASTNode.leavesIncludingSelf(forward: Boolean = true): Sequence<ASTNode> {
424→    val sequence =
